mapper.insert:
insert into tbl_card (
    member_id, card_company, card_number_masked, billing_key, is_default
) values (
    #{memberId}, #{cardCompany}, #{cardNumberMasked}, #{billingKey}, #{isDefault}
)

mapper.update:
update tbl_card
set card_company = #{cardCompany},
    card_number_masked = #{cardNumberMasked},
    billing_key = #{billingKey},
    is_default = #{isDefault}
where id = #{id}
  and member_id = #{memberId}
  and deleted_datetime is null

update tbl_card
set is_default = true
where id = #{cardId}
  and member_id = #{memberId}
  and deleted_datetime is null

update tbl_card
set deleted_datetime = now(),
    is_default = false
where id = #{cardId}
  and member_id = #{memberId}
  and deleted_datetime is null
